// ── Apply features ──────────────────────────────────────────────────────────

let totalFilled = 0;

for (const [slug, features] of Object.entries(FEATURES)) {
  const filePath = path.join(DIR, slug + '.ts');
  if (!fs.existsSync(filePath)) {
    console.log(`SKIP: ${slug} — file not found`);
    continue;
  }

  let src = fs.readFileSync(filePath, 'utf8');

  // Find features section and its items: []
  const featIdx = src.indexOf('features:');
  if (featIdx === -1) {
    console.log(`SKIP: ${slug} — no features section`);
    continue;
  }

  const itemsIdx = src.indexOf('items:', featIdx);
  const after = src.slice(itemsIdx + 6, itemsIdx + 30).trim();
  if (!after.startsWith('[]')) {
    console.log(`SKIP: ${slug} — features already populated`);
    continue;
  }

  // Build items array
  const items = features.map((f, i) => {
    const escapedDesc = f.desc.replace(/'/g, "\\'");
    const escapedTitle = f.title.replace(/'/g, "\\'");
    return `      {
        id: '${i + 1}',
        icon: '${f.icon}',
        title: '${escapedTitle}',
        description: '${escapedDesc}',
        highlighted: ${f.hl ? 'true' : 'false'},
      }`;
  });

  const itemsStr = `items: [\n${items.join(',\n')},\n    ]`;

  // Replace items: [] (and optional trailing comment)
  const emptyPattern = /items:\s*\[\s*\]/;
  const featSection = src.slice(featIdx);
  const match = featSection.match(emptyPattern);
  if (!match) {
    console.log(`SKIP: ${slug} — could not find items: [] pattern in features`);
    continue;
  }

  const replaceStart = featIdx + match.index;
  const replaceEnd = replaceStart + match[0].length;
  const lineEnd = src.indexOf('\n', replaceEnd);
  const trailing = src.slice(replaceEnd, lineEnd).trim();
  let actualEnd = replaceEnd;
  if (trailing.startsWith('//')) actualEnd = lineEnd;

  src = src.slice(0, replaceStart) + itemsStr + src.slice(actualEnd);

  fs.writeFileSync(filePath, src, 'utf8');
  totalFilled++;
  console.log(`FILLED: ${slug} — ${features.length} features`);
}

console.log(`\nTotal files updated: ${totalFilled}`);
